// Lee el binario REAL (aunque esté en filesystem-v2) y lo convierte a base64
const itemIndex = 0;
const binaryProperty = 'data';

// Obtiene el archivo como Buffer
const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryProperty);

// Base64 puro
const base64 = buffer.toString('base64');

// MimeType (si viene octet-stream, lo ajustamos por extensión)
let mimeType = $input.first().binary?.[binaryProperty]?.mimeType || 'application/octet-stream';
const fileName = $input.first().binary?.[binaryProperty]?.fileName || 'file';

if (mimeType === 'application/octet-stream' && fileName.toLowerCase().endsWith('.jpg')) mimeType = 'image/jpeg';
if (mimeType === 'application/octet-stream' && fileName.toLowerCase().endsWith('.jpeg')) mimeType = 'image/jpeg';
if (mimeType === 'application/octet-stream' && fileName.toLowerCase().endsWith('.png')) mimeType = 'image/png';

const dataUrl = `data:${mimeType};base64,${base64}`;

return [{
  json: { base64, dataUrl, mimeType, fileName }
}];

const itemIndex = 0;
const binaryProperty = 'data';

const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryProperty);
const base64 = buffer.toString('base64');

let fileName = $input.first().binary?.[binaryProperty]?.fileName || 'video.mp4';
let mimeType = $input.first().binary?.[binaryProperty]?.mimeType || 'application/octet-stream';

const fn = fileName.toLowerCase();

// Normaliza mime por extensión
if (mimeType === 'application/octet-stream') {
  if (fn.endsWith('.mp4')) mimeType = 'video/mp4';
  else if (fn.endsWith('.mov')) mimeType = 'video/quicktime';
  else if (fn.endsWith('.webm')) mimeType = 'video/webm';
}

// ⚠️ Recomendación: si es .mov, intenta tratarlo como video/mp4 SOLO si ya viene MP4 realmente.
// Si es MOV real, mejor convertir a MP4 (ver punto 4).
return [{ json: { base64, mimeType, fileName } }];

