const binaryProperty = 'data';

const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryProperty);

const base64 = buffer.toString('base64');

// nombre/mime desde binario
let fileName = $input.first().binary?.[binaryProperty]?.fileName || 'file';
let mimeType = $input.first().binary?.[binaryProperty]?.mimeType || 'application/octet-stream';

// si Telegram te trae el nombre real en message.document.file_name,
// puedes pasarlo en el flujo (recomendado)
if ($json?.message?.document?.file_name) fileName = $json.message.document.file_name;
if ($json?.message?.document?.mime_type) mimeType = $json.message.document.mime_type;

// fallback por extensión
const fn = String(fileName).toLowerCase();
if (mimeType === 'application/octet-stream') {
  if (fn.endsWith('.mp4')) mimeType = 'video/mp4';
  else if (fn.endsWith('.mov')) mimeType = 'video/quicktime';
  else if (fn.endsWith('.jpg') || fn.endsWith('.jpeg')) mimeType = 'image/jpeg';
  else if (fn.endsWith('.png')) mimeType = 'image/png';
  else if (fn.endsWith('.pdf')) mimeType = 'application/pdf';
}

return [{ json: { base64, mimeType, fileName } }];

